#include <bits/stdc++.h>
using namespace std;int n;vector<string>g;bool vis[30][30];
int bfs(int si,int sj){int dx[]={0,0,1,-1},dy[]={1,-1,0,0},cnt=0;queue<pair<int,int>>q;q.push({si,sj});vis[si][sj]=1;while(!q.empty()){auto[x,y]=q.front();q.pop();cnt++;for(int k=0;k<4;k++){int nx=x+dx[k],ny=y+dy[k];if(nx<0||ny<0||nx>=n||ny>=n)continue;if(g[nx][ny]=='1'&&!vis[nx][ny]){vis[nx][ny]=1;q.push({nx,ny});}}}return cnt;}
int main(){cin>>n;g.resize(n);for(auto&s:g)cin>>s;vector<int>sz;for(int i=0;i<n;i++)for(int j=0;j<n;j++)if(g[i][j]=='1'&&!vis[i][j])sz.push_back(bfs(i,j));sort(sz.begin(),sz.end());cout<<sz.size()<<"\n";for(int x:sz)cout<<x<<"\n";}
